import numpy as np

def hungarian_algorithm(cost_matrix):
    """
    Assigns tasks to agents to minimize the total cost using the Hungarian algorithm.

    Args:
        cost_matrix: A 2D numpy array representing the cost of assigning each task to each agent.

    Returns:
        A tuple containing:
            - A list of assignments (agent index -> task index).
            - The minimum total cost.
    """
    cost_matrix = np.array(cost_matrix)
    n = cost_matrix.shape[0]
    m = cost_matrix.shape[1]

    if n != m:
      raise ValueError("Cost matrix must be square.")

    # Step 1: Reduce the matrix
    cost_matrix = cost_matrix.copy()
    for i in range(n):
        cost_matrix[i, :] -= np.min(cost_matrix[i, :])
    for j in range(n):
        cost_matrix[:, j] -= np.min(cost_matrix[:, j])

    # Step 2: Cover all zeros with minimum number of lines
    line_count = 0
    row_covered = [False] * n
    col_covered = [False] * n

    def find_uncovered_zero():
      for i in range(n):
        for j in range(n):
          if cost_matrix[i, j] == 0 and not row_covered[i] and not col_covered[j]:
            return i, j
      return None, None

    def cover_zeros():
      nonlocal line_count, row_covered, col_covered

      row_covered = [False] * n
      col_covered = [False] * n
      line_count = 0

      starred_zeros = []
      for i in range(n):
        for j in range(n):
          if cost_matrix[i, j] == 0:

            row_has_star = False
            col_has_star = False
            for r, c in starred_zeros:
              if r == i or c == j:
                if r == i:
                  row_has_star = True
                if c == j:
                  col_has_star = True
                break

            if not row_has_star and not col_has_star:
              starred_zeros.append((i,j))

      line_count = 0
      row_covered = [False] * n
      col_covered = [False] * n
      for r, c in starred_zeros:
        col_covered[c] = True
        line_count +=1

      while line_count < n:
        #Find uncovered zero
        z_row, z_col = find_uncovered_zero()
        if z_row is None:
            #No uncovered zero found.  Adjust matrix
            min_val = np.inf
            for i in range(n):
                for j in range(n):
                    if not row_covered[i] and not col_covered[j]:
                        min_val = min(min_val, cost_matrix[i, j])

            for i in range(n):
                for j in range(n):
                    if not row_covered[i]:
                        cost_matrix[i, j] -= min_val
                    if col_covered[j]:
                        cost_matrix[i, j] += min_val

            continue # find uncovered zero again

        #Prime the zero
        primed_zeros = [(z_row, z_col)]

        #Check if there is a starred zero in the row
        star_col = None
        for r, c in starred_zeros:
            if r == z_row:
                star_col = c
                break

        if star_col is not None:
            #Cover row and uncover column
            row_covered[z_row] = True
            col_covered[star_col] = False
        else:
            #Convert primes to stars
            while True:
                z_row, z_col = primed_zeros[-1]

                #Find starred zero in column
                star_row = None
                for r, c in starred_zeros:
                    if c == z_col:
                        star_row = r
                        break

                if star_row is None:
                    #No starred zero in column
                    break

                #Add primed zero in row of the star
                primed_col = None
                for r,c in primed_zeros:
                  if r == star_row:
                    primed_col = c
                    break

                primed_zeros.append((star_row, primed_col))

            #Unstar starred zeros and star primed zeros
            for r, c in primed_zeros:
                if (r,c) in starred_zeros:
                    starred_zeros.remove((r,c))
                else:
                    starred_zeros.append((r,c))

            line_count = 0
            row_covered = [False] * n
            col_covered = [False] * n

            for r, c in starred_zeros:
                col_covered[c] = True
                line_count +=1


    cover_zeros()

    while line_count < n:
        cover_zeros()

    # Step 3: Find the assignment
    assignments = []
    for r, c in enumerate(col_covered):
      assignments.append(0)

    for r, c in enumerate(col_covered):
        for i in range(n):
            assignment_found = False
            if cost_matrix[i][r] == 0:

                is_duplicate = False
                for key, value in enumerate(assignments):
                  if value == r:
                    is_duplicate = True
                    break

                if not is_duplicate:
                  assignments[i] = r
                  assignment_found = True
                  break
        if not assignment_found:
          print("Assignment failure!")
          return [], np.inf

    # Calculate the minimum cost
    min_cost = 0
    for i, j in enumerate(assignments):
        min_cost += cost_matrix[i, j]

    return assignments, min_cost
